(base / 'ai/prompts.py').write_text('"""\nSystem prompts and fitness knowledge base for the AI coach.\nEdit this file to tune the coach\'s personality and expertise.\n\nReplace the contents of ai/prompts.py with this file.\n"""\n\nimport random\n\n# ── Stoic Quote Library ───────────────────────────────────────────────────────\n\nSTOIC_QUOTES = [\n    # Marcus Aurelius\n    ("You have power over your mind — not outside events. Realize this, and you will find strength.", "Marcus Aurelius"),\n    ("The impediment to action advances action. What stands in the way becomes the way.", "Marcus Aurelius"),\n    ("Waste no more time arguing about what a good man should be. Be one.", "Marcus Aurelius"),\n    ("Confine yourself to the present.", "Marcus Aurelius"),\n    ("Our life is what our thoughts make it.", "Marcus Aurelius"),\n    ("A blazing fire makes flame and brightness out of everything that is thrown into it.", "Marcus Aurelius"),\n    ("Receive without pride, relinquish without struggle.", "Marcus Aurelius"),\n    ("Never let the future disturb you. You will meet it, if you have to, with the same weapons of reason which today arm you against the present.", "Marcus Aurelius"),\n    ("Nowhere can man find a quieter or more untroubled retreat than in his own soul.", "Marcus Aurelius"),\n    ("If it is not right, do not do it; if it is not true, do not say it.", "Marcus Aurelius"),\n    ("Do not indulge in hopes that outrun possibility.", "Marcus Aurelius"),\n    ("Very little is needed to make a happy life; it is all within yourself, in your way of thinking.", "Marcus Aurelius"),\n    ("Loss is nothing else but change, and change is Nature\'s delight.", "Marcus Aurelius"),\n    ("The first rule is to keep an untroubled spirit. The second is to look things in the face and know them for what they are.", "Marcus Aurelius"),\n    ("If someone is able to show me that what I think or do is not right, I will happily change.", "Marcus Aurelius"),\n    # Epictetus\n    ("First say to yourself what you would be; and then do what you have to do.", "Epictetus"),\n    ("He is a wise man who does not grieve for the things which he has not, but rejoices for those which he has.", "Epictetus"),\n    ("Make the best use of what is in your power, and take the rest as it happens.", "Epictetus"),\n    ("No man is free who is not master of himself.", "Epictetus"),\n    ("Seek not the good in external things; seek it in yourself.", "Epictetus"),\n    ("It\'s not what happens to you, but how you react to it that matters.", "Epictetus"),\n    ("He who laughs at himself never runs out of things to laugh at.", "Epictetus"),\n    ("Don\'t explain your philosophy. Embody it.", "Epictetus"),\n    ("Wealth consists not in having great possessions, but in having few wants.", "Epictetus"),\n    # Seneca\n    ("It is not that we have a short time to live, but that we waste a lot of it.", "Seneca"),\n    ("Begin at once to live, and count each separate day as a separate life.", "Seneca"),\n    ("Fire tests gold, suffering tests brave men.", "Seneca"),\n    ("He who is brave is free.", "Seneca"),\n    ("Treat your body rigorously so that it will not be disobedient to the mind.", "Seneca"),\n    ("Luck is what happens when preparation meets opportunity.", "Seneca"),\n    ("It is not the man who has too little, but the man who craves more, that is poor.", "Seneca"),\n    ("We suffer more in imagination than in reality.", "Seneca"),\n    ("Hang on to your youthful enthusiasms — you\'ll be able to use them better when you\'re older.", "Seneca"),\n    ("Let us prepare our minds as if we had come to the very end of life. Let us postpone nothing.", "Seneca"),\n    ("Throw me to the wolves and I will return leading the pack.", "Seneca"),\n]\n\n\ndef get_daily_stoic_quote() -> str:\n    """Return a random Stoic quote formatted for Discord."""\n    quote, author = random.choice(STOIC_QUOTES)\n    return f\'*"{quote}"*\\n— {author}\'\n\n\n# ── System Prompt ─────────────────────────────────────────────────────────────\n\nSYSTEM_PROMPT = """\nYou are CoachRex — Dylan\'s personal AI fitness coach and Stoic thinking partner.\n\nYou are built on two pillars:\n1. **Evidence-based athletic coaching** — data-driven, specific, grounded in exercise science\n2. **Stoic philosophy** — practical wisdom from Marcus Aurelius, Epictetus, and Seneca\n\nYou are not a corporate wellness app. You speak like a knowledgeable training partner who has also read Meditations.\nYou are direct, specific, and occasionally philosophical — but never preachy or cheesy about it.\nStoicism comes through in how you frame setbacks, not in constant quoting.\n\n## About Dylan\n- Primarily runs and lifts weights\n- Occasionally plays golf, basketball, squash, and tennis\n- Regularly uses sauna, sometimes steam room and cold plunge\n- Has roughly one year of WHOOP and Strava data\n- Tracks lifts by messaging you during sessions (e.g., "bench 3x10 at 145")\n- Has been reading Marcus Aurelius — Meditations\n- Based in Eastern Time\n\n## Your Responsibilities\n1. Analyze Dylan\'s WHOOP recovery, sleep, HRV, and strain data\n2. Review his Strava activities (runs, lifts, sports)\n3. Track and log his self-reported lift data\n4. Send daily morning briefs with actionable training intent + a Stoic quote\n5. Send weekly training + Stoic reflection summaries on Sunday evenings\n6. Answer conversational questions about training, recovery, health, and philosophy\n\n## Training Philosophy\n- Polarized training: ~80% easy/aerobic, ~20% hard effort for running\n- Progressive overload for lifting with adequate recovery\n- HRV-guided training: use recovery score to modulate intensity\n- Concurrent training management: balance running and lifting fatigue\n- Recovery is training: sauna, cold plunge, and sleep are as important as the workouts\n- Individual baselines matter more than population averages\n\n## Stoic Philosophy — How to Apply It\n- Frame setbacks as information, not failure: "Red recovery isn\'t punishment — it\'s data."\n- Dichotomy of control: distinguish what Dylan controls (effort, sleep, nutrition) from what he doesn\'t (how his body feels today, race conditions, life disruptions)\n- Voluntary discomfort: the cold plunge, the early run, the hard interval — frame these as Stoic practices\n- Process over outcome: a well-executed training week is success, regardless of what the scale or the clock says\n- Amor fati: a bad week is not a detour — it is part of the path\n- Do NOT be preachy. Drop a Stoic thought when it fits naturally. Let the philosophy serve the coaching, not the other way around.\n\n## Interpreting WHOOP Data\n- Recovery 67–100%: Green — go hard if the plan calls for it\n- Recovery 34–66%: Yellow — moderate effort, avoid pushing limits\n- Recovery 0–33%: Red — easy/rest day, prioritize recovery\n- HRV: Higher than baseline = well-recovered; lower = accumulated fatigue\n- RHR: Elevated RHR (+5 bpm) signals illness, stress, or overtraining\n- Strain 0–21 scale: 0–9 light, 10–13 moderate, 14–17 strenuous, 18–21 all out\n\n## Lift Logging\nWhen Dylan messages something like "bench 3x10 at 145" or "did squats, 4 sets of 185",\nparse it as a lift log. Confirm what you logged. Flag PRs. Track progression.\n\n## Communication Style\n- Morning briefs: concise (4–6 lines). Recovery → training intent → observation → Stoic quote.\n- Sunday reflection: structured but personal. Training week + Stoic framing.\n- Conversational: direct, specific, occasionally philosophical. Never generic.\n- Use Dylan\'s actual numbers when available, not vague generalities.\n- No emojis except 💪 used sparingly. No corporate wellness language.\n""".strip()\n\n\n# ── Daily Brief Prompt ────────────────────────────────────────────────────────\n\nDAILY_BRIEF_PROMPT = """\nGenerate Dylan\'s morning brief based on the data below.\n\nFormat:\n- Line 1: Recovery status with HRV + RHR context (specific numbers)\n- Line 2: Recommended training intent for today (specific — e.g., "easy run under 145 bpm" or "good day to go heavy")\n- Line 3: One notable observation or pattern worth flagging\n- Line 4 (optional): Heads-up based on recent trend\n- Final line: Today\'s Stoic quote → {stoic_quote}\n\nTie the Stoic quote to the training context in one brief sentence if it fits naturally.\nKeep the whole brief under 6 lines. Be specific, not generic.\n\nData:\n{data}\n"""\n\n\n# ── Weekly Summary Prompt ─────────────────────────────────────────────────────\n\nWEEKLY_SUMMARY_PROMPT = """\nGenerate Dylan\'s weekly training summary based on the data below.\n\nCover:\n1. Overall training load and recovery balance this week\n2. Running: volume, intensity distribution, any trends\n3. Lifting: exercises logged, any PRs or regressions noted\n4. Recovery quality: sleep trends, HRV trend, sauna/cold plunge if noted\n5. One key takeaway or recommendation for next week\n\nBe analytical. Reference actual numbers. Keep it tight — readable in 2 minutes.\n\nData:\n{data}\n"""\n\n\n# ── Sunday Stoic Reflection Prompt ────────────────────────────────────────────\n\nSUNDAY_REFLECTION_PROMPT = """\nIt\'s Sunday evening. Generate Dylan\'s weekly Stoic reflection.\n\nThis is different from the weekly training summary — it\'s philosophical.\nLook at his week of training and life through a Stoic lens.\n\nStructure:\n1. Open with a Stoic quote that feels relevant to how his week went (use one from the data context)\n2. Briefly note what he controlled well this week (effort, consistency, recovery habits)\n3. Note what was outside his control that he may have spent energy on unnecessarily\n4. Frame one challenge or setback from the week through a Stoic lens (obstacle is the way, dichotomy of control, amor fati)\n5. Close with one thing to carry into next week — not a training goal, but a mindset\n\nTone: thoughtful, grounded, like a wise coach who has also read Marcus Aurelius.\nNot preachy. Not a lecture. A reflection between two people who both know this stuff.\nKeep it under 10 sentences.\n\nTraining data from this week:\n{data}\n"""\n\n\n# ── Chat Prompt ───────────────────────────────────────────────────────────────\n\nCHAT_PROMPT = """\nDylan says: {message}\n\nRelevant context:\n{context}\n\n{knowledge}\n\nRespond as CoachRex. Be direct and specific.\nIf he\'s logging a lift, confirm it clearly and note any progression.\nIf he\'s asking a coaching question, give a real answer grounded in his data and the knowledge base.\nIf the topic touches on mindset, setbacks, or motivation — a brief Stoic framing is welcome but not required.\n"""\n')
print('✅ Written ai/prompts.py')

# --- ai/coach.py ---
(base / 'ai/coach.py').write_text('"""\nAI Coach — orchestrates data fetching, prompt construction, and Claude calls.\nThis is the brain of the bot.\n\nReplace the contents of ai/coach.py with this file.\n"""\n\nimport logging\nimport json\nfrom datetime import datetime, timedelta\nimport anthropic\n\nfrom ai.prompts import (\n    SYSTEM_PROMPT,\n    DAILY_BRIEF_PROMPT,\n    WEEKLY_SUMMARY_PROMPT,\n    SUNDAY_REFLECTION_PROMPT,\n    CHAT_PROMPT,\n    get_daily_stoic_quote,\n)\nfrom integrations.strava import StravaClient\nfrom integrations.whoop import WhoopClient\nfrom integrations.notion import NotionClient\n\nlogger = logging.getLogger(__name__)\n\n\n# Try to load knowledge retriever — gracefully skips if not set up yet\ntry:\n    from ai.knowledge_retriever import KnowledgeRetriever\n    _retriever = KnowledgeRetriever()\nexcept ImportError:\n    _retriever = None\n    logger.info("Knowledge retriever not available — run ingest_knowledge.py to enable RAG.")\n\n\nclass Coach:\n    def __init__(self, config, db):\n        self.config = config\n        self.db = db\n        self.strava = StravaClient(config)\n        self.whoop = WhoopClient(config)\n        self.notion = NotionClient(config)\n        self.claude = anthropic.AsyncAnthropic(api_key=config.ANTHROPIC_API_KEY)\n        self.model = config.CLAUDE_MODEL\n\n        # Conversation history for multi-turn chat\n        self._conversation: list[dict] = []\n\n    async def _ask_claude(self, user_message: str, use_history: bool = False) -> str:\n        """Send a message to Claude and return the response text."""\n        messages = []\n\n        if use_history:\n            messages = self._conversation.copy()\n\n        messages.append({"role": "user", "content": user_message})\n\n        response = await self.claude.messages.create(\n            model=self.model,\n            max_tokens=1024,\n            system=SYSTEM_PROMPT,\n            messages=messages,\n        )\n\n        reply = response.content[0].text\n\n        if use_history:\n            self._conversation.append({"role": "user", "content": user_message})\n            self._conversation.append({"role": "assistant", "content": reply})\n            # Keep conversation history from growing too large\n            if len(self._conversation) > 40:\n                self._conversation = self._conversation[-40:]\n\n        return reply\n\n    async def _build_context(self, days: int = 7) -> str:\n        """Pull fresh WHOOP + Strava data and format it as context for Claude."""\n        try:\n            snapshot = await self.whoop.get_today_snapshot()\n            recent_activities = await self.strava.get_recent_activities(days=days)\n            recent_lifts = await self.db.get_recent_lifts(days=days)\n            recent_notes = await self.db.get_recent_notes(days=days)\n\n            recovery_summary = self.whoop.summarize_recovery(snapshot.get("recovery"))\n            sleep_summary = self.whoop.summarize_sleep(snapshot.get("sleep"))\n            activity_summaries = [self.strava.summarize_activity(a) for a in recent_activities]\n\n            context_parts = [\n                f"TODAY ({datetime.now().strftime(\'%A, %B %d\')})",\n                f"  {recovery_summary}",\n                f"  {sleep_summary}",\n                "",\n                f"RECENT ACTIVITIES (last {days} days):",\n            ]\n            for act in activity_summaries[:10]:\n                context_parts.append(f"  - {act}")\n\n            if recent_lifts:\n                context_parts.append("")\n                context_parts.append("RECENT LIFTS (self-reported):")\n                for lift in recent_lifts:\n                    context_parts.append(f"  - {lift[\'date\']} | {lift[\'exercise\']} | {lift[\'details\']}")\n\n            if recent_notes:\n                context_parts.append("")\n                context_parts.append("RECENT NOTES:")\n                for note in recent_notes:\n                    context_parts.append(f"  - {note[\'date\']}: {note[\'content\']}")\n\n            return "\\n".join(context_parts)\n\n        except Exception as e:\n            logger.error(f"Error building context: {e}")\n            return "Unable to fetch current data — responding from memory."\n\n    def _retrieve_knowledge(self, query: str) -> str:\n        """Query the RAG knowledge base for relevant content."""\n        if _retriever is None:\n            return ""\n        return _retriever.retrieve(query)\n\n    async def daily_brief(self) -> str:\n        """Generate and return the morning brief message."""\n        context = await self._build_context(days=2)\n        stoic_quote = get_daily_stoic_quote()\n        prompt = DAILY_BRIEF_PROMPT.format(data=context, stoic_quote=stoic_quote)\n        brief = await self._ask_claude(prompt)\n\n        # Log to Notion in the background (best effort)\n        try:\n            snapshot = await self.whoop.get_today_snapshot()\n            rec = snapshot.get("recovery", {}) or {}\n            slp = snapshot.get("sleep", {}) or {}\n            activities = await self.strava.get_recent_activities(days=1)\n\n            score = rec.get("score", {})\n            sleep_score = slp.get("score", {})\n            stage_summary = sleep_score.get("stage_summary", {})\n\n            await self.notion.log_daily_entry(\n                date=datetime.now().strftime("%Y-%m-%d"),\n                summary={\n                    "recovery_score": score.get("recovery_score"),\n                    "hrv": round(score.get("hrv_rmssd_milli", 0), 1),\n                    "rhr": score.get("resting_heart_rate"),\n                    "sleep_hours": round(stage_summary.get("total_in_bed_time_milli", 0) / 3_600_000, 1),\n                    "sleep_efficiency": sleep_score.get("sleep_efficiency_percentage"),\n                    "activities": [self.strava.summarize_activity(a) for a in activities],\n                    "daily_brief": brief,\n                }\n            )\n        except Exception as e:\n            logger.warning(f"Notion log failed silently: {e}")\n\n        return brief\n\n    async def weekly_summary(self) -> str:\n        """Generate and return the weekly training summary message."""\n        context = await self._build_context(days=7)\n        prompt = WEEKLY_SUMMARY_PROMPT.format(data=context)\n        return await self._ask_claude(prompt)\n\n    async def stoic_reflection(self) -> str:\n        """Generate the Sunday evening Stoic reflection."""\n        context = await self._build_context(days=7)\n        prompt = SUNDAY_REFLECTION_PROMPT.format(data=context)\n        return await self._ask_claude(prompt)\n\n    async def chat(self, message: str) -> str:\n        """\n        Handle a conversational message from Dylan.\n        Detects lift logs and stores them; otherwise responds as coach.\n        Injects relevant knowledge base content when available.\n        """\n        # Try to detect a lift log\n        lift = await self._try_parse_lift(message)\n        if lift:\n            await self.db.log_lift(\n                date=datetime.now().strftime("%Y-%m-%d"),\n                exercise=lift["exercise"],\n                details=lift["details"],\n                raw=message,\n            )\n            # Also log to Notion\n            try:\n                await self.notion.log_lift(\n                    date=datetime.now().strftime("%Y-%m-%d"),\n                    exercise=lift["exercise"],\n                    sets_reps_weight=lift["details"],\n                )\n            except Exception:\n                pass\n\n        # Get recent context + knowledge base retrieval\n        context = await self._build_context(days=3)\n        knowledge = self._retrieve_knowledge(message)\n\n        prompt = CHAT_PROMPT.format(\n            message=message,\n            context=context,\n            knowledge=knowledge,\n        )\n        return await self._ask_claude(prompt, use_history=True)\n\n    async def _try_parse_lift(self, message: str) -> dict | None:\n        """\n        Ask Claude to parse a potential lift log from a message.\n        Returns a dict with \'exercise\' and \'details\' if it looks like a lift, else None.\n        """\n        parse_prompt = f"""\nDoes this message describe a weightlifting exercise? If yes, extract:\n- exercise name\n- details (sets, reps, weight as described)\n\nMessage: "{message}"\n\nRespond with JSON only. If it\'s a lift: {{"is_lift": true, "exercise": "...", "details": "..."}}\nIf not: {{"is_lift": false}}\n"""\n        try:\n            raw = await self._ask_claude(parse_prompt)\n            start = raw.find("{")\n            end = raw.rfind("}") + 1\n            data = json.loads(raw[start:end])\n            if data.get("is_lift"):\n                return {"exercise": data["exercise"], "details": data["details"]}\n        except Exception as e:\n            logger.debug(f"Lift parse failed: {e}")\n        return None\n')
print('✅ Written ai/coach.py')

# --- bot/scheduler.py ---
(base / 'bot/scheduler.py').write_text('"""\nScheduler — sends the daily morning brief, weekly training summary,\nand Sunday Stoic reflection automatically.\n\nReplace the contents of bot/scheduler.py with this file.\n"""\n\nimport logging\nfrom datetime import datetime\nimport pytz\nfrom discord.ext import tasks\n\nlogger = logging.getLogger(__name__)\n\n\nclass Scheduler:\n    def __init__(self, bot, config, coach):\n        self.bot = bot\n        self.config = config\n        self.coach = coach\n        self.tz = pytz.timezone(config.TIMEZONE)\n\n        # Parse configured time\n        hour, minute = map(int, config.DAILY_BRIEF_TIME.split(":"))\n        self.brief_hour = hour\n        self.brief_minute = minute\n\n    def start(self):\n        self.check_scheduled_tasks.start()\n        logger.info(f"Scheduler started. Daily brief at {self.config.DAILY_BRIEF_TIME} {self.config.TIMEZONE}")\n\n    @tasks.loop(minutes=1)\n    async def check_scheduled_tasks(self):\n        now = datetime.now(self.tz)\n\n        # Daily morning brief\n        if now.hour == self.brief_hour and now.minute == self.brief_minute:\n            await self._send_daily_brief()\n\n        # Weekly training summary — Sundays at 7:00pm\n        if now.weekday() == 6 and now.hour == 19 and now.minute == 0:\n            await self._send_weekly_summary()\n\n        # Sunday Stoic reflection — Sundays at 8:30pm (after summary)\n        if now.weekday() == 6 and now.hour == 20 and now.minute == 30:\n            await self._send_stoic_reflection()\n\n    async def _send_daily_brief(self):\n        channel = self.bot.get_channel(self.config.DISCORD_CHANNEL_DAILY)\n        if not channel:\n            logger.warning("Daily channel not found.")\n            return\n        logger.info("Sending daily brief...")\n        brief = await self.coach.daily_brief()\n        await channel.send(brief)\n\n    async def _send_weekly_summary(self):\n        channel = self.bot.get_channel(self.config.DISCORD_CHANNEL_DAILY)\n        if not channel:\n            return\n        logger.info("Sending weekly training summary...")\n        summary = await self.coach.weekly_summary()\n        await channel.send(f"**Weekly Training Summary**\\n\\n{summary}")\n\n    async def _send_stoic_reflection(self):\n        channel = self.bot.get_channel(self.config.DISCORD_CHANNEL_DAILY)\n        if not channel:\n            return\n        logger.info("Sending Sunday Stoic reflection...")\n        reflection = await self.coach.stoic_reflection()\n        await channel.send(f"**Sunday Reflection**\\n\\n{reflection}")\n\n    @check_scheduled_tasks.before_loop\n    async def before_loop(self):\n        await self.bot.wait_until_ready()\n')
print('✅ Written bot/scheduler.py')

# --- ai/knowledge_retriever.py ---
(base / 'ai/knowledge_retriever.py').write_text('"""\nKnowledge Retriever\n====================\nProvides semantic search over the ChromaDB fitness knowledge base.\nUsed by ai/coach.py to inject relevant knowledge into Claude prompts.\n\nCopy this file to: ai/knowledge_retriever.py\n"""\n\nimport logging\nfrom pathlib import Path\nfrom typing import Optional\n\nlogger = logging.getLogger(__name__)\n\nCHROMA_PATH = Path(__file__).parent.parent / "data" / "chroma_db"\nCOLLECTION_NAME = "fitness_knowledge"\nEMBEDDING_MODEL = "all-MiniLM-L6-v2"\n\n\nclass KnowledgeRetriever:\n    """Semantic search over the fitness knowledge base."""\n\n    def __init__(self):\n        self._client = None\n        self._collection = None\n        self._model = None\n        self._initialized = False\n\n    def _initialize(self):\n        """Lazy initialization — only loads models when first queried."""\n        if self._initialized:\n            return\n\n        try:\n            import chromadb\n            from sentence_transformers import SentenceTransformer\n\n            self._model = SentenceTransformer(EMBEDDING_MODEL)\n            self._client = chromadb.PersistentClient(path=str(CHROMA_PATH))\n            self._collection = self._client.get_collection(COLLECTION_NAME)\n            self._initialized = True\n            logger.info(f"Knowledge base loaded: {self._collection.count()} chunks")\n\n        except Exception as e:\n            logger.warning(f"Knowledge base not available: {e}. Run ingest_knowledge.py first.")\n            self._initialized = False\n\n    def retrieve(self, query: str, n_results: int = 4) -> str:\n        """\n        Search the knowledge base for content relevant to the query.\n        Returns a formatted string ready to inject into a prompt.\n        Returns empty string if knowledge base is unavailable.\n        """\n        self._initialize()\n\n        if not self._initialized or self._collection is None:\n            return ""\n\n        try:\n            embedding = self._model.encode([query]).tolist()\n            results = self._collection.query(\n                query_embeddings=embedding,\n                n_results=n_results,\n                include=["documents", "metadatas", "distances"],\n            )\n\n            docs = results["documents"][0]\n            metas = results["metadatas"][0]\n            distances = results["distances"][0]\n\n            if not docs:\n                return ""\n\n            # Only include sufficiently relevant results (cosine distance < 0.6)\n            relevant = [\n                (doc, meta, dist)\n                for doc, meta, dist in zip(docs, metas, distances)\n                if dist < 0.6\n            ]\n\n            if not relevant:\n                return ""\n\n            parts = ["RELEVANT FITNESS KNOWLEDGE:"]\n            for doc, meta, dist in relevant:\n                source = meta.get("source", "unknown").replace("_", " ").title()\n                section = meta.get("section", "")\n                parts.append(f"\\n[{source} — {section}]\\n{doc.strip()}")\n\n            return "\\n".join(parts)\n\n        except Exception as e:\n            logger.warning(f"Knowledge retrieval failed: {e}")\n            return ""\n')
print('✅ Written ai/knowledge_retriever.py')

# --- knowledge/ingest_knowledge.py ---
(base / 'knowledge/ingest_knowledge.py').write_text('"""\nRAG Knowledge Base Ingestion Script\n====================================\nReads all markdown files in the knowledge/ directory,\nchunks them into sections, creates embeddings using\nsentence-transformers (runs locally, no API needed),\nand stores in ChromaDB.\n\nUsage:\n    python ingest_knowledge.py\n\nRun this once after adding or updating knowledge files.\nChromaDB persists to disk — no need to re-run unless files change.\n\nInstall dependencies first:\n    pip install chromadb sentence-transformers\n"""\n\nimport os\nimport re\nimport chromadb\nfrom pathlib import Path\nfrom sentence_transformers import SentenceTransformer\n\n# ── Config ────────────────────────────────────────────────────────────────────\nKNOWLEDGE_DIR = Path(__file__).parent  # same folder as this script\nCHROMA_PATH = Path(__file__).parent.parent / "data" / "chroma_db"\nCOLLECTION_NAME = "fitness_knowledge"\nEMBEDDING_MODEL = "all-MiniLM-L6-v2"  # fast, good quality, ~80MB download\nCHUNK_SIZE = 600      # target words per chunk\nCHUNK_OVERLAP = 50    # words of overlap between chunks\n\n\n# ── Chunking ──────────────────────────────────────────────────────────────────\ndef chunk_markdown(text: str, source: str) -> list[dict]:\n    """\n    Split markdown into chunks by section (##) headers.\n    Falls back to word-count chunking if sections are too large.\n    """\n    chunks = []\n\n    # Split by ## headers (level 2 and 3)\n    sections = re.split(r"\\n(?=#{2,3} )", text)\n\n    for section in sections:\n        if not section.strip():\n            continue\n\n        # Extract section title from first line\n        lines = section.strip().splitlines()\n        title = lines[0].lstrip("#").strip() if lines else "General"\n\n        # If section is small enough, keep as-is\n        words = section.split()\n        if len(words) <= CHUNK_SIZE:\n            chunks.append({\n                "text": section.strip(),\n                "source": source,\n                "section": title,\n            })\n        else:\n            # Word-count chunk with overlap\n            for i in range(0, len(words), CHUNK_SIZE - CHUNK_OVERLAP):\n                chunk_words = words[i : i + CHUNK_SIZE]\n                chunks.append({\n                    "text": " ".join(chunk_words),\n                    "source": source,\n                    "section": f"{title} (part {i // (CHUNK_SIZE - CHUNK_OVERLAP) + 1})",\n                })\n\n    return chunks\n\n\n# ── Main ──────────────────────────────────────────────────────────────────────\ndef main():\n    print("Loading embedding model (downloads ~80MB on first run)...")\n    model = SentenceTransformer(EMBEDDING_MODEL)\n\n    print(f"Connecting to ChromaDB at {CHROMA_PATH}...")\n    CHROMA_PATH.mkdir(parents=True, exist_ok=True)\n    client = chromadb.PersistentClient(path=str(CHROMA_PATH))\n\n    # Delete and recreate collection for clean ingest\n    try:\n        client.delete_collection(COLLECTION_NAME)\n        print("Deleted existing collection.")\n    except Exception:\n        pass\n\n    collection = client.create_collection(\n        name=COLLECTION_NAME,\n        metadata={"hnsw:space": "cosine"},\n    )\n\n    # Gather all markdown files\n    md_files = sorted(KNOWLEDGE_DIR.glob("*.md"))\n    if not md_files:\n        print(f"No .md files found in {KNOWLEDGE_DIR}")\n        return\n\n    all_chunks = []\n    for md_file in md_files:\n        print(f"Processing {md_file.name}...")\n        text = md_file.read_text(encoding="utf-8")\n        chunks = chunk_markdown(text, source=md_file.stem)\n        all_chunks.extend(chunks)\n        print(f"  → {len(chunks)} chunks")\n\n    print(f"\\nTotal chunks: {len(all_chunks)}")\n    print("Creating embeddings...")\n\n    texts = [c["text"] for c in all_chunks]\n    embeddings = model.encode(texts, show_progress_bar=True, batch_size=32)\n\n    print("Storing in ChromaDB...")\n    collection.add(\n        ids=[f"chunk_{i}" for i in range(len(all_chunks))],\n        embeddings=embeddings.tolist(),\n        documents=texts,\n        metadatas=[{"source": c["source"], "section": c["section"]} for c in all_chunks],\n    )\n\n    print(f"\\n✅ Done! {len(all_chunks)} chunks stored in ChromaDB at {CHROMA_PATH}")\n    print("You can now run the bot — CoachRex will use this knowledge base.")\n\n\nif __name__ == "__main__":\n    main()\n')
print('✅ Written knowledge/ingest_knowledge.py')


print('\n✅ All files written. Now run:')
print('  pip3 install chromadb sentence-transformers --break-system-packages')
print('  python3 knowledge/ingest_knowledge.py')